export enum AppView {
  DASHBOARD = 'DASHBOARD',
  PLANT_GUIDE = 'PLANT_GUIDE',
  DIAGNOSIS = 'DIAGNOSIS',
  NUTRIENTS = 'NUTRIENTS',
  CHECKLIST = 'CHECKLIST'
}

export interface NutrientSalt {
  name: string;
  chemicalName: string;
  purpose: string;
}

export interface GrowthStage {
  stage: string;
  duration: string;
  ec: string;
  tds: string;
  pH: string;
  notes: string;
}

export interface PlantData {
  name: string;
  category: string;
  system: string;
  stages: GrowthStage[];
  spacing: string;
  light: string;
  temp: string;
  humidity: string;
  nutrients: NutrientSalt[];
  mixingOrder: string[];
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzePlantImage = async (base64Image: string) => {
  const model = 'gemini-3-flash-preview';
  const prompt = `Act as a professional hydroponics consultant and plant doctor. Analyze this plant image.
  Identify:
  1. Possible nutrient deficiencies (Nitrogen, P, K, Ca, Mg, Fe).
  2. Diseases, pests, or fungal issues.
  3. Symptoms in simple Hinglish and English.
  4. Treatment (Nutrient correction, foliar spray, organic/chemical solutions).
  5. Confidence level (0-100%).
  6. Emergency actions if critical.

  Format the response in clear Markdown with headings, tables, and warnings. Use simple language for Indian farmers. Mention if this applies to Hydroponics only.`;

  const imagePart = {
    inlineData: {
      mimeType: "image/jpeg",
      data: base64Image,
    },
  };

  const response = await ai.models.generateContent({
    model,
    contents: { parts: [imagePart, { text: prompt }] },
  });

  return response.text;
};

export const getPlantGuide = async (plantName: string) => {
  const model = 'gemini-3-flash-preview';
  const prompt = `Provide a comprehensive professional hydroponic guide for: ${plantName}.
  Include:
  1. Plant Category (Leafy/Fruiting/Root/Herb).
  2. Recommended Hydroponic System (NFT/DWC/Kratky/etc.).
  3. Growth Stages (Germination, Veg, Flowering, Harvest time).
  4. Nutrient Formula (Salts with chemical names).
  5. Table for EC/TDS/pH values for each stage.
  6. Mixing order (A/B Solution method).
  7. Spacing, Light (PPFD), Temp, Humidity.
  8. Common mistakes.
  9. Pro-tips for Indian climate.

  Format with clear headings, tables, and emojis. Use English + Hinglish terms for clarity.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text;
};

