import React, { useState, useRef } from 'react';
import { analyzePlantImage } from '../services/geminiService';

const PlantDiagnosis: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!image) return;
    setLoading(true);
    try {
      const base64Data = image.split(',')[1];
      const analysis = await analyzePlantImage(base64Data);
      setResult(analysis);
    } catch (err) {
      console.error(err);
      alert("Analysis failed. Please check your connection.");
    } finally {
      setLoading(false);
    }
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="space-y-6">
      <div className="text-center">
        <h2 className="text-2xl font-bold text-slate-800">AI Plant Doctor 🩺</h2>
        <p className="text-slate-500 mt-2">Upload a photo of leaves or roots for instant diagnosis.</p>
      </div>

      <div className="bg-white p-8 rounded-2xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center transition-all hover:border-emerald-300">
        {!image ? (
          <div className="text-center py-10">
            <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-4">
              <span className="text-4xl text-emerald-600">📸</span>
            </div>
            <p className="text-slate-600 font-medium">Capture or Upload Leave Image</p>
            <p className="text-xs text-slate-400 mt-1">Make sure the leaf is in focus</p>
            <button 
              onClick={triggerUpload}
              className="mt-6 bg-emerald-600 text-white px-6 py-2 rounded-lg font-bold shadow-lg hover:bg-emerald-700 transition-colors"
            >
              Take Photo
            </button>
          </div>
        ) : (
          <div className="w-full">
            <img src={image} alt="Target Plant" className="w-full max-h-80 object-cover rounded-xl shadow-md mb-6" />
            <div className="flex gap-4">
              <button 
                onClick={triggerUpload}
                disabled={loading}
                className="flex-1 bg-slate-100 text-slate-700 px-6 py-2 rounded-lg font-bold hover:bg-slate-200 transition-colors disabled:opacity-50"
              >
                Retake
              </button>
              <button 
                onClick={handleAnalyze}
                disabled={loading}
                className="flex-1 bg-emerald-600 text-white px-6 py-2 rounded-lg font-bold shadow-lg hover:bg-emerald-700 transition-colors disabled:opacity-50 flex items-center justify-center"
              >
                {loading ? (
                  <>
                    <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    Analyzing...
                  </>
                ) : 'Run AI Analysis'}
              </button>
            </div>
          </div>
        )}
        <input 
          type="file" 
          ref={fileInputRef} 
          onChange={handleFileChange} 
          accept="image/*" 
          className="hidden" 
        />
      </div>

      {result && (
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm animate-fade-in">
          <div className="flex items-center space-x-2 mb-4 border-b pb-4">
            <span className="text-2xl">📋</span>
            <h3 className="text-xl font-bold text-slate-800">Diagnosis Report</h3>
          </div>
          <div className="prose prose-slate max-w-none prose-sm whitespace-pre-wrap leading-relaxed text-slate-700">
            {result}
          </div>
          <div className="mt-8 pt-4 border-t border-slate-100">
            <p className="text-xs text-slate-400 italic">⚠️ Note: AI diagnosis is a tool for guidance. For commercial farms, periodic lab testing of water and plant tissue is recommended.</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default PlantDiagnosis;

import React, { useState } from 'react';
import { getPlantGuide } from '../services/geminiService';

const PlantGuide: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(false);
  const [guide, setGuide] = useState<string | null>(null);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchTerm.trim()) return;
    setLoading(true);
    try {
      const result = await getPlantGuide(searchTerm);
      setGuide(result);
    } catch (err) {
      alert("Failed to fetch guide.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="text-center mb-8">
        <h2 className="text-2xl font-bold text-slate-800">Hydroponic Master Guide 📚</h2>
        <p className="text-slate-500 mt-2">Get exact nutrient salts, EC levels, and climate tips.</p>
      </div>

      <form onSubmit={handleSearch} className="flex gap-2">
        <input 
          type="text" 
          placeholder="Enter plant (e.g., Lettuce, Cherry Tomato, Bok Choy)..." 
          className="flex-1 border border-slate-300 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-emerald-500 transition-all shadow-sm"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        <button 
          type="submit"
          disabled={loading}
          className="bg-emerald-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-emerald-700 shadow-md transition-all flex items-center gap-2 disabled:opacity-50"
        >
          {loading ? 'Fetching...' : 'Get Guide'}
        </button>
      </form>

      {guide ? (
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="prose prose-emerald max-w-none whitespace-pre-wrap text-slate-700">
            {guide}
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-8">
          {[
            { n: 'Lettuce', i: '🥬' },
            { n: 'Tomato', i: '🍅' },
            { n: 'Basil', i: '🌿' },
            { n: 'Strawberry', i: '🍓' }
          ].map(p => (
            <button 
              key={p.n}
              onClick={() => { setSearchTerm(p.n); /* Manual search trigger logic */ }}
              className="bg-white p-4 rounded-xl border border-slate-100 flex flex-col items-center hover:shadow-md hover:border-emerald-200 transition-all"
            >
              <span className="text-3xl mb-2">{p.i}</span>
              <span className="text-sm font-semibold text-slate-700">{p.n}</span>
            </button>
          ))}
        </div>
      )}

      <div className="bg-emerald-50 p-5 rounded-xl border border-emerald-100">
        <h4 className="font-bold text-emerald-800 text-sm mb-2 uppercase tracking-wider">💡 Pro Knowledge Corner</h4>
        <p className="text-emerald-700 text-sm">
          In high temperatures (like Indian summers), plants transpire more. Keep EC slightly lower (10-20% less) to prevent salt buildup and allow plants to absorb more water.
        </p>
      </div>
    </div>
  );
};

export default PlantGuide;

import React, { useState } from 'react';

const DailyChecklist: React.FC = () => {
  const [logs, setLogs] = useState([
    { id: 1, task: 'Measure pH Level', done: false, time: 'Morning' },
    { id: 2, task: 'Check EC/TDS Strength', done: false, time: 'Morning' },
    { id: 3, task: 'Verify Water Temperature', done: false, time: 'Afternoon' },
    { id: 4, task: 'Inspect Roots for slime/browning', done: false, time: 'Daily' },
    { id: 5, task: 'Check Pump Flow Rate', done: false, time: 'Daily' },
  ]);

  const toggleLog = (id: number) => {
    setLogs(logs.map(l => l.id === id ? { ...l, done: !l.done } : l));
  };

  return (
    <div className="space-y-6">
      <div className="bg-emerald-900 text-white p-6 rounded-2xl shadow-lg">
        <h2 className="text-2xl font-bold mb-1">Growth Log 📅</h2>
        <p className="opacity-80 text-sm">Consistency is the bridge between seedlings and harvest.</p>
        <div className="mt-4 flex items-center space-x-4">
          <div className="flex-1 h-2 bg-emerald-800 rounded-full overflow-hidden">
            <div 
              className="h-full bg-emerald-400 transition-all duration-500" 
              style={{ width: `${(logs.filter(l => l.done).length / logs.length) * 100}%` }}
            ></div>
          </div>
          <span className="text-xs font-bold">{logs.filter(l => l.done).length}/{logs.length} Tasks</span>
        </div>
      </div>

      <div className="space-y-3">
        {logs.map(log => (
          <div 
            key={log.id} 
            onClick={() => toggleLog(log.id)}
            className={`p-4 rounded-xl border transition-all cursor-pointer flex items-center justify-between ${
              log.done ? 'bg-slate-50 border-slate-200' : 'bg-white border-slate-200 hover:border-emerald-300'
            }`}
          >
            <div className="flex items-center space-x-4">
              <div className={`w-6 h-6 rounded-md border flex items-center justify-center transition-colors ${
                log.done ? 'bg-emerald-500 border-emerald-500 text-white' : 'bg-white border-slate-300'
              }`}>
                {log.done && '✓'}
              </div>
              <div>
                <p className={`text-sm font-semibold ${log.done ? 'text-slate-400 line-through' : 'text-slate-800'}`}>
                  {log.task}
                </p>
                <p className="text-[10px] text-slate-400 font-medium uppercase">{log.time}</p>
              </div>
            </div>
            {log.done && <span className="text-[10px] text-emerald-600 font-bold">COMPLETED</span>}
          </div>
        ))}
      </div>

      <div className="mt-10 p-6 bg-slate-100 rounded-2xl">
        <h3 className="font-bold text-slate-800 mb-4">Add Manual Entry</h3>
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="text-xs text-slate-500 font-bold uppercase">Current pH</label>
            <input type="number" step="0.1" placeholder="6.0" className="w-full p-2 rounded-lg border border-slate-300 text-sm" />
          </div>
          <div className="space-y-1">
            <label className="text-xs text-slate-500 font-bold uppercase">Current EC</label>
            <input type="number" step="0.1" placeholder="1.8" className="w-full p-2 rounded-lg border border-slate-300 text-sm" />
          </div>
        </div>
        <button className="w-full mt-4 bg-slate-800 text-white py-2 rounded-lg text-sm font-bold">Save Reading</button>
      </div>
    </div>
  );
};

export default DailyChecklist;

import React, { useState } from 'react';
import { AppView } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import PlantDiagnosis from './components/PlantDiagnosis';
import PlantGuide from './components/PlantGuide';
import NutrientManager from './components/NutrientManager';
import DailyChecklist from './components/DailyChecklist';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<AppView>(AppView.DASHBOARD);

  const renderContent = () => {
    switch (activeView) {
      case AppView.DASHBOARD:
        return <Dashboard />;
      case AppView.DIAGNOSIS:
        return <PlantDiagnosis />;
      case AppView.PLANT_GUIDE:
        return <PlantGuide />;
      case AppView.NUTRIENTS:
        return <NutrientManager />;
      case AppView.CHECKLIST:
        return <DailyChecklist />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <Layout activeView={activeView} setActiveView={setActiveView}>
      {renderContent()}
    </Layout>
  );
};

export default App;

