              onClick={handleGenerateAiFormula}
              disabled={isAiLoading}
              className="bg-emerald-600 text-white px-4 py-3 rounded-xl font-bold text-xs shadow-md disabled:opacity-50"
            >
              {isAiLoading ? '...' : t.genBtn}
            </button>
          </div>
        )}

