import React, { useState } from 'react';
import { AppView, Language, UserRole } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import PlantDiagnosis from './components/PlantDiagnosis';
import PlantGuide from './components/PlantGuide';
import NutrientManager from './components/NutrientManager';
import DailyChecklist from './components/DailyChecklist';
import Login from './components/Login';
import AdminSettings from './components/AdminSettings';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<AppView>(AppView.DASHBOARD);
  const [language, setLanguage] = useState<Language>('en');
  const [userRole, setUserRole] = useState<UserRole | null>(null);

  const handleLogin = (role: UserRole) => {
    setUserRole(role);
    setActiveView(AppView.DASHBOARD); // Reset view on login
  };

  const handleLogout = () => {
    setUserRole(null);
  };

  if (!userRole) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (activeView) {
      case AppView.DASHBOARD:
        return <Dashboard language={language} />;
      case AppView.DIAGNOSIS:
        return <PlantDiagnosis language={language} />;
      case AppView.PLANT_GUIDE:
        return <PlantGuide language={language} />;
      case AppView.NUTRIENTS:
        return <NutrientManager language={language} />;
      case AppView.CHECKLIST:
        return <DailyChecklist language={language} />;
      case AppView.ADMIN_SETTINGS:
        return userRole === 'admin' ? <AdminSettings language={language} /> : <Dashboard language={language} />;
      default:
        return <Dashboard language={language} />;
    }
  };

  return (
    <Layout 
      activeView={activeView} 
      setActiveView={setActiveView} 
      language={language} 
      setLanguage={setLanguage}
      userRole={userRole}
      onLogout={handleLogout}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  PLANT_GUIDE = 'PLANT_GUIDE',
  DIAGNOSIS = 'DIAGNOSIS',
  NUTRIENTS = 'NUTRIENTS',
  CHECKLIST = 'CHECKLIST',
  ADMIN_SETTINGS = 'ADMIN_SETTINGS'
}

export type Language = 'en' | 'hi';
export type UserRole = 'admin' | 'user';

export interface UserAccount {
  username: string;
  password: string; // stored simply for this demo, usually should be hashed
  expiryDate: string; // ISO string
  createdDate: string; // ISO string
}

export interface NutrientSalt {
  name: string;
  chemicalName: string;
  purpose: string;
}

export interface GrowthStage {
  stage: string;
  duration: string;
  ec: string;
  tds: string;
  pH: string;
  notes: string;
}

import React, { useState, useEffect } from 'react';
import { UserRole, UserAccount } from '../types';

interface LoginProps {
  onLogin: (role: UserRole) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  // Initialize default user if storage is empty (First run)
  useEffect(() => {
    const storedUsers = localStorage.getItem('hydro_users');
    if (!storedUsers) {
      const defaultUser: UserAccount = {
        username: 'user',
        password: 'Bhushan@Sawarkar',
        createdDate: new Date().toISOString(),
        expiryDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString() // 30 days from now
      };
      localStorage.setItem('hydro_users', JSON.stringify([defaultUser]));
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // 1. Admin Login (Hardcoded)
    if (username === 'admin' && password === '9325445135') {
      onLogin('admin');
      return;
    }

    // 2. User Login (Dynamic List)
    const storedUsersRaw = localStorage.getItem('hydro_users');
    const users: UserAccount[] = storedUsersRaw ? JSON.parse(storedUsersRaw) : [];

    const foundUser = users.find(u => u.username === username);

    if (foundUser) {
      if (foundUser.password === password) {
        // Check Validity
        const now = new Date();
        const expiry = new Date(foundUser.expiryDate);

        if (now > expiry) {
          setError('Account Expired. Validity (30 Days) over. Please contact Admin.');
        } else {
          onLogin('user');
        }
      } else {
        setError('Invalid Password');
      }
    } else {
      setError('User ID not found');
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
      <div className="bg-white rounded-3xl shadow-2xl overflow-hidden max-w-md w-full flex flex-col md:flex-row">
        <div className="p-8 w-full">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-emerald-100 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-4">
              🌿
            </div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tight">HydroSense AI</h1>
            <p className="text-slate-500 font-medium text-sm mt-1">Professional Hydroponic System</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Login ID</label>
              <input
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-semibold outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
                placeholder="Enter ID"
              />
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-semibold outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
                placeholder="••••••••"
              />
            </div>

            {error && (
              <div className="bg-red-50 text-red-600 text-xs font-bold px-4 py-3 rounded-xl flex items-center">
                ⚠️ {error}
              </div>
            )}

            <button
              type="submit"
              className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-4 rounded-xl shadow-lg shadow-emerald-200 transition-all transform hover:scale-[1.02] active:scale-[0.98] mt-4"
            >
              Sign In
            </button>
          </form>

          <div className="mt-8 text-center">
            <p className="text-[10px] text-slate-400 font-medium">
              Protected System • Authorized Personnel Only
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { Language, UserAccount } from '../types';

const AdminSettings: React.FC<{ language: Language }> = ({ language }) => {
  // State for adding user
  const [newUsername, setNewUsername] = useState('');
  const [newPassword, setNewPassword] = useState('');

  // State for user list
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [msg, setMsg] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = () => {
    const stored = localStorage.getItem('hydro_users');
    if (stored) {
      setUsers(JSON.parse(stored));
    }
  };

  const showMsg = (text: string, type: 'success' | 'error') => {
    setMsg({ type, text });
    setTimeout(() => setMsg(null), 3000);
  };

  const handleAddUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newUsername || !newPassword) {
      showMsg('Please fill username and password', 'error');
      return;
    }

    if (users.some(u => u.username === newUsername)) {
      showMsg('User ID already exists', 'error');
      return;
    }

    const newUser: UserAccount = {
      username: newUsername,
      password: newPassword,
      createdDate: new Date().toISOString(),
      expiryDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString() // 30 Days from now
    };

    const updatedUsers = [...users, newUser];
    localStorage.setItem('hydro_users', JSON.stringify(updatedUsers));
    setUsers(updatedUsers);
    setNewUsername('');
    setNewPassword('');
    showMsg('User added with 30 days validity!', 'success');
  };

  const handleDelete = (usernameToDelete: string) => {
    if (confirm('Are you sure you want to delete this user?')) {
      const updatedUsers = users.filter(u => u.username !== usernameToDelete);
      localStorage.setItem('hydro_users', JSON.stringify(updatedUsers));
      setUsers(updatedUsers);
      showMsg('User deleted', 'success');
    }
  };

  const handleRenew = (usernameToRenew: string) => {
    const updatedUsers = users.map(u => {
      if (u.username === usernameToRenew) {
        return {
          ...u,
          expiryDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString() // Add 30 days from TODAY
        };
      }
      return u;
    });
    localStorage.setItem('hydro_users', JSON.stringify(updatedUsers));
    setUsers(updatedUsers);
    showMsg(`Validity extended for ${usernameToRenew}`, 'success');
  };

  const t = {
    en: {
      title: "Admin Panel 🛡️",
      sub: "User Access Management",
      addUserTitle: "Add New User",
      userListTitle: "Existing Users",
      username: "Login ID",
      password: "Password",
      createBtn: "Create User (30 Days)",
      expires: "Expires",
      status: "Status",
      action: "Actions",
      active: "Active",
      expired: "Expired",
      renewBtn: "Renew (30 Days)",
      deleteBtn: "Delete"
    },
    hi: {
      title: "एडमिन पैनल 🛡️",
      sub: "यूजर एक्सेस मैनेजमेंट",
      addUserTitle: "नया यूजर जोड़ें",
      userListTitle: "मौजूदा यूजर्स",
      username: "लॉगिन आईडी",
      password: "पासवर्ड",
      createBtn: "यूजर बनाएं (30 दिन)",
      expires: "समाप्त",
      status: "स्थिति",
      action: "कार्य",
      active: "सक्रिय",
      expired: "समाप्त (Expired)",
      renewBtn: "नवीनीकरण करें (30 दिन)",
      deleteBtn: "हटाएं"
    }
  }[language];

  return (
    <div className="space-y-6 pb-20">
      <div className="bg-slate-800 text-white p-8 rounded-3xl shadow-xl relative overflow-hidden">
         <div className="relative z-10">
            <h2 className="text-3xl font-black mb-2">{t.title}</h2>
            <p className="text-slate-300 font-medium">{t.sub}</p>
         </div>
         <div className="absolute right-[-20px] top-[-30px] opacity-10 text-[150px]">🔒</div>
      </div>

      {/* Message Banner */}
      {msg && (
        <div className={`p-4 rounded-xl font-bold text-center animate-fade-in ${msg.type === 'success' ? 'bg-emerald-100 text-emerald-800' : 'bg-red-100 text-red-800'}`}>
          {msg.text}
        </div>
      )}

      <div className="grid md:grid-cols-2 gap-6">
        {/* ADD USER FORM */}
        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm h-fit">
          <h3 className="text-xl font-bold text-slate-800 mb-4 flex items-center gap-2">
            <span className="bg-emerald-100 text-emerald-600 w-8 h-8 flex items-center justify-center rounded-lg text-sm">＋</span>
            {t.addUserTitle}
          </h3>
          <form onSubmit={handleAddUser} className="space-y-4">
            <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">{t.username}</label>
                <input 
                    type="text" 
                    value={newUsername}
                    onChange={(e) => setNewUsername(e.target.value)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-semibold outline-none focus:ring-2 focus:ring-emerald-500"
                    placeholder="e.g. farmer01"
                />
            </div>
            <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">{t.password}</label>
                <input 
                    type="text" 
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-semibold outline-none focus:ring-2 focus:ring-emerald-500"
                    placeholder="Set password"
                />
            </div>
            <button 
                type="submit" 
                className="w-full bg-emerald-600 hover:bg-emerald-700 text-white py-3 rounded-xl font-bold shadow-lg transition-all"
            >
                {t.createBtn}
            </button>
            <p className="text-[10px] text-slate-400 text-center">
              Validity is automatically set to 30 days from creation.
            </p>
          </form>
        </div>

        {/* USER LIST */}
        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
          <h3 className="text-xl font-bold text-slate-800 mb-4 flex items-center gap-2">
            <span className="bg-blue-100 text-blue-600 w-8 h-8 flex items-center justify-center rounded-lg text-sm">👥</span>
            {t.userListTitle}
          </h3>

          <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2">
            {users.length === 0 && (
              <p className="text-slate-400 text-sm text-center py-4">No users found.</p>
            )}

            {users.map((user) => {
              const isExpired = new Date() > new Date(user.expiryDate);
              const daysLeft = Math.ceil((new Date(user.expiryDate).getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));

              return (
                <div key={user.username} className="border border-slate-100 rounded-xl p-4 hover:border-emerald-200 transition-colors bg-slate-50/50">
                  <div className="flex justify-between items-start mb-2">
                    <div>
                      <h4 className="font-bold text-slate-800">{user.username}</h4>
                      <p className="text-xs text-slate-500 font-mono">Pwd: {user.password}</p>
                    </div>
                    <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${isExpired ? 'bg-red-100 text-red-600' : 'bg-emerald-100 text-emerald-600'}`}>
                      {isExpired ? t.expired : t.active}
                    </span>
                  </div>

                  <div className="flex items-center gap-2 text-xs text-slate-500 mb-3">
                    <span>⏳ {isExpired ? 'Expired on:' : 'Expires:'} {new Date(user.expiryDate).toLocaleDateString()}</span>
                    {!isExpired && <span className="text-slate-400">({daysLeft} days left)</span>}
                  </div>

                  <div className="flex gap-2">
                    <button 
                      onClick={() => handleRenew(user.username)}
                      className="flex-1 bg-blue-600 hover:bg-blue-700 text-white py-2 rounded-lg text-xs font-bold shadow-sm"
                    >
                      {t.renewBtn}
                    </button>
                    <button 
                      onClick={() => handleDelete(user.username)}
                      className="px-3 bg-red-100 hover:bg-red-200 text-red-600 py-2 rounded-lg text-xs font-bold"
                    >
                      🗑️
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminSettings;
